using System;using System.Collections.Generic;using System.Threading;using System.Threading.Tasks;using FluentAssertions;using KUKULCAN.Kernel.Abstractions.Interfaces.Domain;using KUKULCAN.Kernel.Abstractions.Interfaces.Infrastructure;using Xunit;namespace KUKULCAN.Kernel.Tests.Infrastructure{    public class ReadRepositoryTests    {        private sealed class E : IEntity<Guid> { public Guid Id => Guid.NewGuid(); }        private sealed class FakeRepo : IReadRepository<E, Guid>        {            public Task<E?> GetByIdAsync(Guid id, CancellationToken cancellationToken = default) => Task.FromResult<E?>(new E());            public Task<IReadOnlyList<E>> ListAllAsync(CancellationToken cancellationToken = default) => Task.FromResult((IReadOnlyList<E>)new List<E>{ new E() });            public Task<bool> ExistsAsync(Guid id, CancellationToken cancellationToken = default) => Task.FromResult(true);            public Task<long> CountAsync(CancellationToken cancellationToken = default) => Task.FromResult(1L);        }        [Fact]        public async Task FakeRepo_ImplementsMethods()        {            var r = new FakeRepo();            var e = await r.GetByIdAsync(Guid.NewGuid());            e.Should().NotBeNull();            (await r.ListAllAsync()).Count.Should().BeGreaterThan(0);            (await r.ExistsAsync(Guid.NewGuid())).Should().BeTrue();            (await r.CountAsync()).Should().Be(1);        }    }}